const jobs = $input.first().json.data.jobs;

if (!jobs || jobs.length === 0) {
  return [{ json: { error: "No jobs found today", jobs: [] } }];
}

const parsed = jobs.map((job, index) => {
  // Truncate description to ~500 words so Mistral handles it well
  let desc = (job.job_description || "No description available")
    .replace(/[\r\n\t]+/g, ' ')
    .replace(/"/g, "'")
    .replace(/\\/g, '')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  const words = desc.split(/\s+/);
  if (words.length > 1200) {
    desc = words.slice(0, 1200).join(" ") + "...";
}

  // Pre-compute location fit so the LLM doesn't have to judge geography itself
  const corridor = ["london", "kitchener", "waterloo", "cambridge", "hamilton", "woodstock", "brantford", "guelph", "chatham", "st. thomas"];
  const gta = [
    "toronto", "oakville", "mississauga", "vaughan", "richmond hill",
    "markham", "scarborough", "brampton", "milton"];
  const outer_gta = [
    "etobicoke",    // shows up separately in some postings
    "north york",   // same
    "pickering",
    "ajax",
    "whitby",
    "oshawa",       // Durham region;
    "newmarket",
    "aurora",
    "barrie", 
  ];
  const cityLower = (job.job_city || "").toLowerCase();
  const countryLower = (job.job_country || "").toLowerCase();
  const isCanada = countryLower === "ca" || countryLower === "canada";
  let locationFitHint;
  if (corridor.includes(cityLower)) locationFitHint = 9;
  else if (gta.includes(cityLower)) locationFitHint = 8;
  else if (outer_gta.includes(cityLower)) locationFitHint = 7;
  else if (job.job_is_remote && isCanada) locationFitHint = 8;
  else if (cityLower === "vancouver") locationFitHint = 6;
  else if (isCanada) locationFitHint = 4;
  else if (!cityLower && !countryLower) locationFitHint = 5;
  else locationFitHint = 1;

  return {
    id: index + 1,
    title: job.job_title || "Unknown Title",
    company: job.employer_name || "Unknown Company",
    location: job.job_city
      ? `${job.job_city}, ${job.job_state || ""} ${job.job_country || ""}`
      : (job.job_is_remote ? "Remote" : "Not specified"),
    is_remote: job.job_is_remote || false,
    employment_type: job.job_employment_type || "Not specified",
    description: desc,
    apply_link: job.job_apply_link || "#",
    posted: job.job_posted_at_datetime_utc || "Unknown",
    salary_min: job.job_min_salary || null,
    salary_max: job.job_max_salary || null,
    location_fit_hint: locationFitHint,
  };
});

// Return each job as a separate item for the loop
return parsed.map(job => ({ json: job }));

// Ollama's /api/chat returns the model's reply at message.content.
// With the schema enforced via "format", this should already be valid JSON,
// but keep the try/catch as a safety net for a malformed or empty response.
const rawContent = $input.first().json.message.content;
const originalJob = $('Loop Over Items').first().json;

let scored;
try {
    scored = JSON.parse(rawContent);
} catch (e) {
    scored = {
        score: 5,
        reason: "Could not parse LLM response. Manual review recommended.",
        key_skills: [],
        experience_level: "unknown",
        salary_estimate: "N/A",
        red_flags: ["LLM parsing failed"],
        dimensions: null
    };
}
scored.dimensions = scored.dimensions || {};
scored.dimensions.location_fit = originalJob.location_fit_hint;
return [{
    json: {
        title: originalJob.title,
        company: originalJob.company,
        location: originalJob.location,
        is_remote: originalJob.is_remote,
        employment_type: originalJob.employment_type,
        apply_link: originalJob.apply_link,
        posted: originalJob.posted,
        salary_min: originalJob.salary_min,
        salary_max: originalJob.salary_max,
        match_score: scored.score,
        match_reason: scored.reason,
        key_skills: scored.key_skills,
        experience_level: scored.experience_level,
        salary_estimate: scored.salary_estimate,
        red_flags: scored.red_flags,
        dimensions: scored.dimensions || null
    }
}];

const allJobs = $input.all().map(item => item.json);

const jobSummaries = allJobs.map(job =>
`- [Score: ${job.match_score}/10] ${job.title} at ${job.company} (${job.location})
Reason: ${job.match_reason}
Skills needed: ${(job.key_skills || []).join(", ")}
Red flags: ${(job.red_flags || []).length > 0 ? job.red_flags.join(", ") : "None"}`
).join("\n\n");

const prompt = `You are a career assistant agent. Below are today's job postings, already scored by
    relevance to the candidate (Mike).

    Write a concise daily market summary with these sections:
    1. HEADLINE — one sentence on today's overall market (how many jobs, general quality)
    2. TRENDS — patterns you notice across postings (common skills asked for, salary ranges, remote vs on-site, seniority mix)
    3. ACTION ITEMS — specific things the candidate should do today (skills to brush up, search adjustments)

    Do not list, name, or describe individual job postings. A separate, exact table of the top-ranked
    postings is already included below your summary, so do not restate job titles, companies, or
    scores; your job is only the high-level read on today's market.

    Keep the tone professional but direct. Be specific and actionable.

    TODAY'S SCORED JOBS:
    ${jobSummaries}

    Write the summary now.`;

return [{ json: { prompt: prompt, jobs: allJobs } }];

const prompt = $input.first().json.prompt;

return [{
  json: {
    requestBody: JSON.stringify({
      model: 'mistral:latest',
      stream: false,
      prompt: prompt
    }),
    jobs: $input.first().json.jobs
  }
}];

const digest = $input.first().json.response;
const jobs = $('Prepare Digest Prompt').first().json.jobs;

const today = new Date().toLocaleDateString('en-CA', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Build a simple HTML email
const rankedJobs = [...jobs].sort((a, b) => b.match_score - a.match_score);
const strongMatches = rankedJobs.filter(j => j.match_score >= 7);
const topJobs = (strongMatches.length >= 3 ? strongMatches : rankedJobs.slice(0, 3))
    .map(j =>
        `<tr>
        <td style="padding:8px;border-bottom:1px solid #eee;">
            <strong>${j.title}</strong><br/>
            ${j.company} — ${j.location}<br/>
            <span style="color:#2d7d46;font-weight:bold;">Score: ${j.match_score}/10</span><br/>
            <em>${j.match_reason}</em><br/>
            <a href="${j.apply_link}" style="color:#1a73e8;">Apply Now →</a>
        </td>
        </tr>`
    ).join("");

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">
  <h1 style="color:#1a1a1a;border-bottom:2px solid #1a73e8;padding-bottom:10px;">
    Job Agent Daily Digest
  </h1>
  <p style="color:#666;font-size:14px;">${today} — ${jobs.length} jobs analyzed</p>

  <div style="background:#f8f9fa;padding:16px;border-radius:8px;margin:16px 0;">
    ${digest.replace(/\n/g, "<br/>")}
  </div>

  ${topJobs ? `
  <h2 style="color:#1a1a1a;">🏆 Top Matches</h2>
  <table style="width:100%;border-collapse:collapse;">${topJobs}</table>
  ` : ""}

  <hr style="margin:24px 0;border:none;border-top:1px solid #eee;"/>
  <p style="color:#999;font-size:12px;">
    Generated by your local Job Board Agent
  </p>
</div>`;

return [{
  json: {
    subject: `Job Digest — ${today} — ${jobs.length} jobs, ${jobs.filter(j => j.match_score >= 7).length} strong matches`,
    html: html
  }
}];

